type User ={
    /**
     * User id defined by the database 
     */
    id: number,
    /**
     * user's email as entered when created 
     */
    email: string,
    /**
     * user's firstname as entered when created 
     */
    first_name: string,
    /**
     * user's lastname as entered when created 
     */
    last_name:string,
    /**
     * user's lastname as entered when created 
     */
    password: string
     /**
     * user's lastname as entered when created 
     */
    auth_token: string



}